/**
 * Módulo 1 - Upload de Procuração
 * Formulário para upload de PDF com dados de procuração
 */

import { useState } from 'react'
import { Button } from '../../components/ui/button'
import { Input } from '../../components/ui/input'
import { Label } from '../../components/ui/label'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../../components/ui/card'
import { Alert, AlertDescription } from '../../components/ui/alert'
import { uploadProxyPdf } from '../../services/adminApi'

export default function UploadProxy({ onSuccess }) {
  const [file, setFile] = useState(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState('')
  const [manualData, setManualData] = useState(null)

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0]
    if (selectedFile && selectedFile.name.endsWith('.pdf')) {
      setFile(selectedFile)
      setError('')
      setManualData(null)
    } else {
      setFile(null)
      setError('Por favor, selecione um arquivo PDF válido')
    }
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    
    if (!file) {
      setError('Selecione um arquivo PDF')
      return
    }
    
    setLoading(true)
    setError('')
    setSuccess('')
    setManualData(null)
    
    const result = await uploadProxyPdf(file)
    
    if (result.success) {
      setSuccess(`Procuração cadastrada com sucesso! Dados extraídos automaticamente.`)
      setFile(null)
      document.getElementById('pdf-file').value = ''
      if (onSuccess) onSuccess()
    } else if (result.requiresManual) {
      setManualData(result.extractedData)
      setError(result.error)
    } else {
      setError(result.error)
    }
    
    setLoading(false)
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Upload de Procuração</CardTitle>
        <CardDescription>
          Faça upload de um arquivo PDF da procuração. O sistema tentará extrair automaticamente:
          apartamento, email do outorgante, CPF do outorgante e CPF do outorgado.
        </CardDescription>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          {error && (
            <Alert variant="destructive">
              <AlertDescription>{error}</AlertDescription>
            </Alert>
          )}
          
          {success && (
            <Alert className="bg-green-50 border-green-500">
              <AlertDescription className="text-green-700">{success}</AlertDescription>
            </Alert>
          )}
          
          {manualData && (
            <Alert className="bg-yellow-50 border-yellow-500">
              <AlertDescription className="text-yellow-700">
                <p className="font-bold">Dados extraídos parcialmente:</p>
                <p>Apartamento: {manualData?.apartment || 'Não identificado'}</p>
                <p>Email outorgante: {manualData?.grantor_email || 'Não identificado'}</p>
                <p>CPF outorgante: {manualData?.grantor_cpf || 'Não identificado'}</p>
                <p>CPF outorgado: {manualData?.grantee_cpf || 'Não identificado'}</p>
                <p className="mt-2">Por favor, verifique o PDF e tente novamente com um arquivo mais legível.</p>
              </AlertDescription>
            </Alert>
          )}
          
          <div className="space-y-2">
            <Label htmlFor="pdf-file">Arquivo PDF da Procuração</Label>
            <Input
              id="pdf-file"
              type="file"
              accept=".pdf"
              onChange={handleFileChange}
              required
            />
          </div>
          
          <Button type="submit" className="w-full" disabled={loading}>
            {loading ? 'Processando...' : 'Upload e Cadastrar Procuração'}
          </Button>
        </form>
      </CardContent>
    </Card>
  )
}
